     4|
     5|/**
     6| * IVX Deployment Watchdog
     7| *
     8| * Closes the deployment chain end-to-end and writes machine-readable proof:
     9| *
    10| *   Rork Sandbox  ->  GitHub (main)  ->  Render deploy  ->  Production API (/version)
    11| *
    12| * For each run it:
    13| *   1. Reads the local commit (git HEAD).
    14| *   2. Pushes the working tree to GitHub via expo/sync-github.mjs (single atomic commit).
    15| *   3. Reads back the GitHub `main` head commit (Git Refs API).
    16| *   4. Triggers a Render deploy and polls until it is live (or reuses the latest deploy).
    17| *   5. Reads the production commit from `${PRODUCTION_BASE_URL}/version`.
    18| *   6. Compares every node and writes DEPLOYMENT_PROOF.json at the repo root.
    19| *
    20| * It NEVER fabricates a match. If a node cannot be reached or a credential is
    21| * missing, it records the EXACT failing node + the EXACT missing permission,
    22| * sets `match:false`, and exits non-zero.
    23| *
    24| * Usage:
    25| *   node deploy/deployment-watchdog.mjs              # verify-only (no push/deploy)
    26| *   node deploy/deployment-watchdog.mjs --deploy     # push + deploy + verify
    27| *   node deploy/deployment-watchdog.mjs --deploy --wait 600
    28| */
    29|
    30|import { execFileSync } from 'node:child_process';
    31|import { writeFileSync } from 'node:fs';
    32|import { join, dirname } from 'node:path';
    33|import { fileURLToPath } from 'node:url';
    34|
    35|const __dirname = dirname(fileURLToPath(import.meta.url));
    36|const REPO_ROOT = join(__dirname, '..');
    37|const PROOF_PATH = join(REPO_ROOT, 'DEPLOYMENT_PROOF.json');
    38|
    39|const args = process.argv.slice(2);
    40|const DO_DEPLOY = args.includes('--deploy');
    41|const waitIdx = args.indexOf('--wait');
    42|const MAX_WAIT_SECONDS = waitIdx !== -1 && args[waitIdx + 1] ? parseInt(args[waitIdx + 1], 10) : 480;
    43|
    44|const GITHUB_API = 'https://api.github.com';
    45|const RENDER_API = 'https://api.render.com/v1';
    46|
    47|const env = process.env;
    48|const GITHUB_TOKEN = env.GITHUB_TOKEN;
    49|const GITHUB_BRANCH = env.GITHUB_BRANCH || 'main';
    50|const RENDER_API_KEY = env.RENDER_API_KEY;
    51|const RENDER_SERVICE_ID = env.RENDER_SERVICE_ID;
    52|const PRODUCTION_BASE_URL = (env.PRODUCTION_BASE_URL || env.EXPO_PUBLIC_IVX_API_BASE_URL || '').replace(/\/$/, '');
    53|
    54|/** @returns {string} owner/repo slug or '' */
    55|function parseRepoSlug(value) {
    56|  const v = String(value || '').trim();
    57|  if (!v) return '';
    58|  if (/^[^/\s]+\/[^/\s]+$/.test(v)) return v.replace(/\.git$/i, '');
    59|  const m = v.match(/github\.com[/:]([^/\s]+)\/([^/.\s]+)(?:\.git)?/i);
    60|  return m ? `${m[1]}/${m[2]}` : '';
    61|}
    62|const REPO_SLUG = parseRepoSlug(env.GITHUB_REPO) || parseRepoSlug(env.GITHUB_REPO_URL);
    63|
    64|function gitHead() {
    65|  try {
    66|    return execFileSync('git', ['rev-parse', 'HEAD'], { cwd: REPO_ROOT }).toString().trim();
    67|  } catch {
    68|    return '';
    69|  }
    70|}
    71|
    72|function short(sha) {
    73|  return sha ? String(sha).slice(0, 8) : '';
    74|}
    75|
    76|const proof = {
    77|  generatedBy: 'deploy/deployment-watchdog.mjs',
    78|  verificationTimestamp: new Date().toISOString(),
    79|  mode: DO_DEPLOY ? 'deploy+verify' : 'verify-only',
    80|  localCommit: '',
    81|  syncedCommit: '',
    82|  githubCommit: '',
    83|  renderCommit: '',
    84|  productionCommit: '',
    85|  match: false,
    86|  failingNode: null,
    87|  missingPermission: null,
    88|  nodes: {
    89|    sandbox: { ok: false, detail: '' },
    90|    githubPush: { ok: false, detail: '' },
    91|    github: { ok: false, detail: '' },
    92|    render: { ok: false, detail: '' },
    93|    production: { ok: false, detail: '' },
    94|  },
    95|};
    96|
    97|/** Records a failing node + missing permission, writes proof, and exits 1. */
    98|function fail(node, missingPermission, detail) {
    99|  proof.failingNode = node;
   100|  proof.missingPermission = missingPermission;
   101|  if (proof.nodes[node]) proof.nodes[node].detail = detail;
