   103|  console.error(`\nFAILING NODE: ${node}`);
   104|  console.error(`MISSING PERMISSION: ${missingPermission}`);
   105|  console.error(`DETAIL: ${detail}`);
   106|  process.exit(1);
   107|}
   108|
   109|function flush() {
   110|  writeFileSync(PROOF_PATH, JSON.stringify(proof, null, 2) + '\n');
