   113|async function ghFetch(path) {
   114|  const res = await fetch(`${GITHUB_API}${path}`, {
   115|    headers: {
   116|      Authorization: `Bearer ${GITHUB_TOKEN}`,
   117|      Accept: 'application/vnd.github+json',
   118|      'User-Agent': 'ivx-deployment-watchdog',
   119|    },
   120|  });
   121|  return res;
   122|}
   123|
   124|async function renderFetch(path, init = {}) {
   125|  const res = await fetch(`${RENDER_API}${path}`, {
   126|    ...init,
   127|    headers: {
   128|      Authorization: `Bearer ${RENDER_API_KEY}`,
   129|      Accept: 'application/json',
   130|      'Content-Type': 'application/json',
   131|      ...(init.headers || {}),
   132|    },
   133|  });
   134|  return res;
