   159|      execFileSync(process.execPath, [join(REPO_ROOT, 'expo', 'sync-github.mjs'),
   160|        '--message', `watchdog deploy ${short(proof.localCommit)} ${new Date().toISOString()}`],
   161|        { cwd: join(REPO_ROOT, 'expo'), env: { ...env }, stdio: 'inherit', timeout: 180_000 });
   162|      proof.nodes.githubPush.ok = true;
   163|      proof.nodes.githubPush.detail = 'sync-github.mjs completed';
   164|    } catch (err) {
