   188|    }
   189|  } else {
   190|    proof.nodes.github.detail = !GITHUB_TOKEN
   191|      ? 'GITHUB_TOKEN missing from process env'
   192|      : 'GITHUB_REPO_URL missing from process env';
   193|  }
   194|
   195|  // ── Node 4: Render deploy ──────────────────────────────────────────────
   196|  if (RENDER_API_KEY && RENDER_SERVICE_ID) {
