     1|/**
     2| * IVX Phase 1 — Durable agent store.
     3| *
     4| * The multi-agent framework (Block 25) kept tasks / audit / memory / handoffs in
     5| * in-process Maps that reset on every server restart. This store makes them
     6| * durable so the agent team never forgets its work between deploys.
     7| *
     8| * Design mirrors the proven unified-executive-memory store:
     9| *   logs/audit/agent-state/agent-state.json     materialised snapshot (fast read)
    10| *   logs/audit/agent-state/agent-state.jsonl     append-only event log (forensics)
    11| *
    12| * Honesty + safety rules:
    13| *   - Pure filesystem I/O, no AI/network, never throws into callers (a failed
    14| *     persist is swallowed so remembering can never break the action that
    15| *     produced it).
    16| *   - The framework stays the source of truth at runtime; this store only
    17| *     snapshots it and rehydrates it on boot.
    18| */
    19|import { appendFile, mkdir, readFile, rename, writeFile } from 'node:fs/promises';
    20|import path from 'node:path';
    21|
    22|export const AGENT_DURABLE_STORE_MARKER = 'ivx-agent-durable-store-2026-06-09';
    23|
    24|const DIR = path.join(process.cwd(), 'logs', 'audit', 'agent-state');
    25|const STATE_PATH = path.join(DIR, 'agent-state.json');
    26|const TMP_PATH = path.join(DIR, 'agent-state.json.tmp');
    27|const LOG_PATH = path.join(DIR, 'agent-state.jsonl');
    28|
    29|/** The full durable snapshot of the multi-agent framework. */
    30|export type AgentStateSnapshot = {
    31|  marker: string;
    32|  savedAt: string;
    33|  tasks: unknown[];
    34|  audit: unknown[];
    35|  memory: unknown[];
    36|  handoffs: unknown[];
    37|};
    38|
    39|let writeChain: Promise<void> = Promise.resolve();
    40|
    41|async function ensureDir(): Promise<void> {
    42|  await mkdir(DIR, { recursive: true });
    43|}
    44|
    45|/** Serialize writes so concurrent persists can't race or corrupt the snapshot. */
    46|function enqueueWrite<T>(task: () => Promise<T>): Promise<T> {
    47|  const run = writeChain.then(task, task);
    48|  writeChain = run.then(
    49|    () => undefined,
    50|    () => undefined,
    51|  );
    52|  return run;
    53|}
    54|
    55|/** Persist a full snapshot atomically (temp-file + rename). Never throws. */
    56|export function persistAgentState(snapshot: Omit<AgentStateSnapshot, 'marker' | 'savedAt'>): Promise<void> {
    57|  return enqueueWrite(async () => {
    58|    try {
    59|      await ensureDir();
    60|      const full: AgentStateSnapshot = {
    61|        marker: AGENT_DURABLE_STORE_MARKER,
    62|        savedAt: new Date().toISOString(),
    63|        tasks: snapshot.tasks,
    64|        audit: snapshot.audit,
    65|        memory: snapshot.memory,
    66|        handoffs: snapshot.handoffs,
    67|      };
    68|      await writeFile(TMP_PATH, JSON.stringify(full), 'utf8');
    69|      await rename(TMP_PATH, STATE_PATH);
    70|    } catch {
    71|      // Best-effort: a failed persist must never break the agent action.
    72|    }
    73|  });
    74|}
