    76|/** Append a single lifecycle event for forensics. Never throws. */
    77|export async function appendAgentEvent(event: Record<string, unknown>): Promise<void> {
    78|  try {
    79|    await ensureDir();
    80|    await appendFile(LOG_PATH, `${JSON.stringify({ ...event, at: event.at ?? new Date().toISOString() })}\n`, 'utf8');
    81|  } catch {
    82|    // Forensic log is best-effort.
    83|  }
    84|}
